Here is a Playwright script in Node.js that performs the described task. It opens the website, performs the search, paginates through the results, and extracts the required data. The script runs headlessly and outputs the results as an array of JSON objects.

```javascript
const { chromium } = require('playwright');
const crypto = require('crypto');

(async () => {
  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext();
  const page = await context.newPage();

  // Open the website
  await page.goto('https://inmobiliariaiparralde.com/');

  // Select "tipo de inmueble = piso"
  await page.selectOption('select[name="tipo_inmueble"]', { label: 'Piso' });

  // Select "municipio = Hendaye"
  await page.selectOption('select[name="municipio"]', { label: 'Hendaye' });

  // Click on the Search button
  await page.click('button[type="submit"]');

  // Wait for the results to load
  await page.waitForSelector('.result-listing');

  const results = [];
  let hasNextPage = true;

  while (hasNextPage) {
    // Extract data from the current page
    const listings = await page.$$('.result-item'); // Adjust selector based on the website's structure

    for (const listing of listings) {
      const title = await listing.$eval('.listing-title', el => el.textContent.trim());
      const price = await listing.$eval('.listing-price', el => el.textContent.trim());
      const location = await listing.$eval('.listing-location', el => el.textContent.trim());
      const detailUrl = await listing.$eval('a.listing-link', el => el.href);
      const timestamp = new Date().toISOString();
      const stableId = crypto

Hash('md5').update(detailUrl).digest('hex');

      results.push({ title, price, location, detailUrl, timestamp, stableId });
    }

    // Check if there is a next page and navigate to it
    const nextPageButton = await page.$('.pagination-next:not(.disabled)');
    if (nextPageButton) {
      await nextPageButton.click();
      await page.waitForTimeout(2000); // Wait for the next page to load
    } else {
      hasNextPage = false;
    }
  }

  // Close the browser
  await browser.close();

  // Output the results as JSON
  console.log(JSON.stringify(results, null, 2));
})();
```

### Steps in the Script:
1. Launch a headless Chromium browser.
2. Navigate to the website.
3. Select the appropriate options for "tipo de inmueble" and "municipio".
4. Click the search button and wait for the results to load.
5. Extract the required data (title, price, location, detail URL, timestamp, and stable ID) from each listing on the current page.
6. Check if there is a next page and navigate to it if available.
7. Repeat the extraction process for all pages.
8. Close the browser and output the results as an array of JSON objects.

### Notes:
- Replace the CSS selectors (e.g., `.result-listing`, `.listing-title`, `.listing-price`, etc.) with the actual selectors from the website's HTML structure.
- The `stableId` is generated using an MD5 hash of the `detailUrl` to ensure uniqueness.
- Add error handling as needed for production use.
